mapper.select:
SELECT uu.id, uu.user_id, uu.artifact_id, uu.media_type AS mediaType, uu.file_url AS fileUrl,
       uu.caption, uu.location_taken AS locationTaken, uu.status, uu.like_count AS likeCount,
       uu.audit_by AS auditBy, uu.audit_time AS auditTime, uu.reject_reason AS rejectReason, uu.created_at,
       u.username, u.avatar_url AS userAvatar,
       a.title_zh AS artifactName
FROM user_uploads uu
LEFT JOIN users u ON uu.user_id = u.id
LEFT JOIN artifacts a ON uu.artifact_id = a.id

    AND uu.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')

    AND uu.media_type = #{mediaType}
    AND uu.status = #{status}

        AND uu.created_at >= #{startTime}


        AND uu.created_at <= #{endTime}


ORDER BY uu.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM user_uploads uu
LEFT JOIN users u ON uu.user_id = u.id

    AND uu.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')

    AND uu.media_type = #{mediaType}
    AND uu.status = #{status}

        AND uu.created_at >= #{startTime}


        AND uu.created_at <= #{endTime}
